create table if not exists public.guides (
  id bigint generated by default as identity primary key,
  slug text not null unique,
  title text not null,
  subtitle text not null default '',
  read_time_minutes integer not null default 10,
  hero_image_url text,
  body text not null default '',
  is_published boolean not null default true,
  created_at timestamptz not null default now(),
  updated_at timestamptz not null default now()
);

create index if not exists guides_published_created_at_idx on public.guides (is_published, created_at desc);

alter table public.guides enable row level security;

drop policy if exists "guides_select_published_authenticated" on public.guides;
create policy "guides_select_published_authenticated"
on public.guides
for select
to authenticated
using (is_published = true);

insert into public.guides (slug, title, subtitle, read_time_minutes, hero_image_url, body, is_published)
values
  ('guide-1', 'Global Gardeners Mini Guide ~ 1', 'A gentle guide for everyday gardeners', 10, '/images/figma/placeholder-expired.png', 'This little guide was created to bring gardeners together - beginners, experts, and everyone in between. Gardening is a shared journey, shaped by the people who teach us, inspire us, and remind us to slow down and notice the small, beautiful things. Global Gardeners was built with that spirit in mind: a place where knowledge is shared freely, where stories matter, and where community comes first.' || E'\n\n' || 'Inside these pages, you''ll find gentle guidance, practical tips, and wisdom from some of the creators who have shaped our own gardening paths. They are part of the foundation of this community, and we''re grateful to share their voices with you.' || E'\n\n' || 'Whether you''re tending a single houseplant or a full backyard garden, we''re glad you''re here. Take what resonates, return to it as the seasons change, and let it be a companion as you grow.' || E'\n\n' || 'Welcome to our world. We''re so happy to have you with us.' || E'\n\n' || '- Vicki, Founder of Global Gardeners', true),
